def request_data(item): return {"id":item.id,"employee_id":item.employee_id,"employee_name":f"{item.employee.first_name} {item.employee.last_name}".strip(),"leave_type_id":item.leave_type_id,"leave_type":item.leave_type.name,"start_date":item.start_date.isoformat(),"end_date":item.end_date.isoformat(),"total_days":float(item.total_days),"reason":item.reason,"status":item.status,"reviewer_note":item.reviewer_note}
def type_data(item): return {"id":item.id,"name":item.name,"code":item.code,"description":item.description,"days_per_year":float(item.days_per_year),"is_paid":item.is_paid,"requires_attachment":item.requires_attachment,"is_active":item.is_active,"count_type":item.count_type,"special_types":item.special_types or []}
def year_data(item): return {"id":item.id,"year":item.year,"start_date":item.start_date.isoformat(),"end_date":item.end_date.isoformat(),"status":item.status}
def group_data(item): return {"id":item.id,"name":item.name,"leave_types":[type_data(value) for value in item.leave_types],"total_leave":sum(float(value.days_per_year) for value in item.leave_types),"employee_count":0}
def policy_data(item): return {"id":item.id,"name":item.name,"count_type":item.count_type,"considerable_hours":float(item.considerable_hours),"adjusted_days":float(item.adjusted_days),"description":item.description,"is_active":item.is_active}
def holiday_data(item): return {"id":item.id,"name":item.name,"description":item.description,"start_date":item.holiday_date.isoformat(),"end_date":(item.end_date or item.holiday_date).isoformat(),"department_id":item.department_id,"department":item.department.name if item.department else "All Departments","is_paid":item.is_paid}
